### Quick Start

\`\`\`typescript
import { AgenaClient } from '@agena/sdk';

// Initialize the client
const agena = new AgenaClient({
  apiKey: 'your-token-here',
});

// Create a task — AI agents will generate code and open a PR
const task = await agena.tasks.create({
  title: 'Add user avatar upload',
  description: 'Allow users to upload and crop a profile avatar image',
});

console.log('Task created:', task.id, task.status);

// Poll for completion
const interval = setInterval(async () => {
  const updated = await agena.tasks.get(task.id);
  console.log('Status:', updated.status);

  if (updated.status === 'completed') {
    console.log('PR ready:', updated.pr_url);
    clearInterval(interval);
  }
}, 5000);
\`\`\`

#### Running a Flow

\`\`\`typescript
// Execute a visual automation flow
const run = await agena.flows.run({ flow_id: 1 });

// Check the result
const result = await agena.flows.getRun(run.id);
console.log('Steps:', result.steps.map(s => s.status));
\`\`\`

#### Monitoring Agents

\`\`\`typescript
// Watch AI agents work in real-time
const live = await agena.agents.liveStatus(task.id);
live.agents.forEach(agent => {
  console.log(agent.role, '→', agent.status);
});
// PM → completed
// Developer → running
// Reviewer → pending
\`\`\`
